function validate(args, output) {
    const n = args[0];
    const sums = args[1];
    if (!Array.isArray(output) || output.length !== n) return false;
    const m = output.length;
    const computed = [];
    for (let mask = 0; mask < (1 << m); mask++) {
        let s = 0;
        for (let i = 0; i < m; i++) {
            if (mask & (1 << i)) s += output[i];
        }
        computed.push(s);
    }
    const cnt = new Map();
    for (const v of computed) cnt.set(v, (cnt.get(v) || 0) + 1);
    for (const v of sums) {
        if (!cnt.has(v) || cnt.get(v) === 0) return false;
        cnt.set(v, cnt.get(v) - 1);
    }
    for (const v of cnt.values()) {
        if (v !== 0) return false;
    }
    return true;
}

