from collections import Counter

class Solution:
    def recoverArray(self, n, sums):
        sums = sorted(sums)
        result = []
        for _ in range(n):
            diff = sums[1] - sums[0]
            cnt = Counter(sums)
            group0 = []
            group1 = []
            for s in sums:
                if cnt[s] <= 0:
                    continue
                if cnt.get(s + diff, 0) > 0:
                    cnt[s] -= 1
                    cnt[s + diff] -= 1
                    group0.append(s)
                    group1.append(s + diff)
            if 0 in group0:
                result.append(diff)
                sums = group0
            else:
                result.append(-diff)
                sums = group1
        return result

