var recoverArray = function(n, sums) {
    sums = sums.slice().sort((a, b) => a - b);
    const result = [];
    for (let iter = 0; iter < n; iter++) {
        const diff = sums[1] - sums[0];
        const cnt = new Map();
        for (const s of sums) cnt.set(s, (cnt.get(s) || 0) + 1);
        const group0 = [];
        const group1 = [];
        for (const s of sums) {
            if ((cnt.get(s) || 0) <= 0) continue;
            const partner = s + diff;
            if ((cnt.get(partner) || 0) > 0) {
                cnt.set(s, cnt.get(s) - 1);
                cnt.set(partner, cnt.get(partner) - 1);
                group0.push(s);
                group1.push(partner);
            }
        }
        if (group0.includes(0)) {
            result.push(diff);
            sums = group0;
        } else {
            result.push(-diff);
            sums = group1;
        }
    }
    return result;
